const trackerNames = $input.last().json.trackerNames;
const message = $("Set conversation parameters").last().json.userMessage;
if(message.toLowerCase() === "preciso de suporte em outro tópico" || message.toLowerCase() === (trackerNames.length + 1).toString()) {
  return {
    index: 1
  };
}
if(message.toLowerCase() === "encerrar atendimento" || message.toLowerCase() === (trackerNames.length + 2).toString()) {
  return {
    index: 2
  };
}
const indexByName = trackerNames.map((name) => name.toLowerCase()).indexOf(message);
const indexNumber = indexByName !== -1 ? indexByName : parseInt(message);
if(isNaN(indexNumber)) {
  return {
    index: 3
  }
}
if(indexNumber < 1 || indexNumber > trackerNames.length + 2) {
  return {
    index: 3
  }
}
if(indexNumber > trackerNames.length) {
  return {
    index: indexNumber - trackerNames.length
  }
}
return {
  index: 0
};

const messages = $("Fetch history").last().json.messages;
const states = $("Define states").last().json.states
for(let i = messages.length - 1; i >= 0; i--) {
  const message = messages[i].system;
  if(message) {
    return {
      currentState: message
    }
  }
}
return {
  currentState: Object.keys(states)[0]
}

const message = $('Fetch history').last().json.messages.find((message) => message.system && message.system === "account_selection");
if(!message) {
  return {
    index: 3
  }
}
const userMessage = $('Set conversation parameters').last().json.userMessage;
const aiMessage = message.ai.substring(242);
const options = aiMessage.split("\n");
const selectedOption = options.find((option) => option.split(".")[0] === userMessage || option.split(".")[1].trim().toLowerCase() === userMessage.toLowerCase());
if(!selectedOption) {
  return {
    index: 3
  }
}
const optionParts = selectedOption.substring(3).split(':');
const optionIndex = parseInt(selectedOption.substring(0, 1));
console.log(selectedOption, optionIndex);
if(optionIndex >= options.length - 1) {
  return {
    index: optionIndex - options.length + 2
  }
}
return {
  index: 0,
  email: optionParts[1].trim()
}

